/**
 * A plugin that makes shapes draggable / droppable.
 *
 */
export default class MoveEvents {
    static $inject: string[];
    /**
     * @param eventBus
     * @param dragging
     * @param modeling
     * @param selection
     * @param rules
     */
    constructor(eventBus: EventBus, dragging: Dragging, modeling: Modeling, selection: Selection, rules: Rules);
    start: (event: MouseEvent | TouchEvent, element: Shape, activate?: boolean, context?: any) => boolean;
}

type Element = import("../../core/Types.js").ElementLike;
type Shape = import("../../core/Types.js").ShapeLike;
type Dragging = import("../dragging/Dragging.js").default;
type EventBus = import("../../core/EventBus.js").default;
type Modeling = import("../modeling/Modeling.js").default;
type Rules = import("../rules/Rules.js").default;
type Selection = import("../selection/Selection.js").default;